def get_music_temp_path():
    """
    将嵌入的背景音乐数据解码到临时文件并返回路径
    如果没有嵌入数据，则尝试查找文件
    """
    # 首先尝试使用嵌入的数据
    if BACKGROUND_MUSIC_DATA and BACKGROUND_MUSIC_DATA.strip():
        try:
            # 创建临时文件
            temp_dir = tempfile.gettempdir()
            temp_path = os.path.join(temp_dir, "word_learning_background.mp3")
            
            # 解码并写入
            import base64
            music_data = base64.b64decode(BACKGROUND_MUSIC_DATA.strip())
            with open(temp_path, 'wb') as f:
                f.write(music_data)
            
            logger.info(f"背景音乐已从嵌入数据解码到: {temp_path}")
            return temp_path
        except Exception as e:
            logger.warning(f"从嵌入数据解码背景音乐失败: {e}")
    
    # 如果嵌入数据不可用，尝试查找文件
    music_file = find_music_file()
    if music_file:
        logger.info(f"使用找到的背景音乐文件: {music_file}")
        return music_file
    
    logger.warning("未找到背景音乐文件或嵌入数据")
    return None

# 内置词库加载器（整合版）
class SchoolDictionary:
    def __init__(self, index_path=None):
        self.index_path = index_path
        self.title = ""
        self.grades = []
        self._by_id = {}
        self._loaded = False
        self._data = None

    def load(self):
        if self._loaded:
            return
        try:
            # 优先尝试从嵌入数据加载
            self._data = load_embedded_dictionary()
            self.title = self._data.get("title", "内置词库")
            self.grades = self._data.get("grades", [])
            self._by_id = {grade["id"]: grade for grade in self.grades}
            self._loaded = True
            return
        except Exception as e:
            logger.warning(f"从嵌入数据加载失败: {e}")
        
        # 如果嵌入数据加载失败，尝试从文件加载
       
        
        raise FileNotFoundError("无法加载内置词库")

    def stages(self):
        self.load()
        seen = []
        for grade in self.grades:
            stage = grade["stage"]
            if stage not in seen:
                seen.append(stage)
        return seen

    def books_for_stage(self, stage):
        self.load()
        return [grade for grade in self.grades if grade["stage"] == stage]

    def get_book(self, book_id):
        self.load()
        return self._by_id.get(book_id)

    def word_count(self):
        self.load()
        return sum(len(grade["words"]) for grade in self.grades)

