# Constants
TRANSLATE_URL = "https://translate.googleapis.com/translate_a/single"
YOUDAO_SUGGEST_URL = "https://dict.youdao.com/suggest"
BAIDU_SUG_URL = "https://fanyi.baidu.com/sug"
# 有道发音API
YOUDAO_PRONUNCIATION_URL = "https://dict.youdao.com/dictvoice?type=0&audio={word}"
# 百度发音API
BAIDU_PRONUNCIATION_URL = "https://fanyi.baidu.com/gettts?lan=en&text={word}&spd=3&source=web"
USER_AGENT = "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36"
CHINESE_PATTERN = re.compile(r"[\u4e00-\u9fff\u3400-\u4dbf]")
JAPANESE_KANA_PATTERN = re.compile(r"[\u3040-\u30ff]")
ENGLISH_PATTERN = re.compile(r"^[A-Za-z][A-Za-z\s\-'.]*$")
HTTP_TIMEOUT = 10
MAX_INPUT_LENGTH = 500
MAX_ANSWER_LENGTH = 100
CORRECT_ANSWER_DELAY_MS = 800
WRONG_ANSWER_DELAY_MS = 1500
