def normalize_english(english):
    english = english.strip()
    english = re.sub(r"\s+", " ", english)
    return english.split("\n", 1)[0].strip()


def split_input_items(text):
    return [item.strip() for item in text.replace(",", "，").split("，") if item.strip()]


def split_chinese_items(text):
    return split_input_items(text)


def contains_chinese(text):
    return bool(CHINESE_PATTERN.search(text))


def contains_japanese_kana(text):
    return bool(JAPANESE_KANA_PATTERN.search(text))


def is_mostly_english(text):
    text = normalize_english(text)
    if not text:
        return False
    if contains_chinese(text):
        return False
    letters = sum(1 for char in text if char.isalpha())
    return letters > 0 and ENGLISH_PATTERN.match(text) is not None


def validate_english_input(text, field_name="输入"):
    text = normalize_english(text)
    if not text:
        raise ValueError(f"{field_name}不能为空")
    if not is_mostly_english(text):
        raise ValueError(f"{field_name}必须是英文，请勿输入中文")
    return text


def validate_chinese_input(text, field_name="输入"):
    text = text.strip()
    if not text:
        raise ValueError(f"{field_name}不能为空")
    if not contains_chinese(text):
        raise ValueError(f"{field_name}必须是中文，请勿输入英文")
    if re.search(r"[A-Za-z]", text):
        raise ValueError(f"{field_name}不能中英混写")
    return text


def detect_input_language(text):
    text = text.strip()
    if not text:
        raise ValueError("输入不能为空")

    has_chinese = contains_chinese(text)
    has_english = bool(re.search(r"[A-Za-z]", text))

    if has_chinese and has_english:
        raise ValueError(f"「{text}」不能中英混写")
    if contains_japanese_kana(text):
        raise ValueError(f"「{text}」请输入纯中文或纯英文")
    if has_chinese:
        return "zh"
    if is_mostly_english(text):
        return "en"
    raise ValueError(f"「{text}」请输入纯中文或纯英文")


def validate_translate_items(text):
    items = split_input_items(text)
    if not items:
        raise ValueError("请输入中文或英文")
    return [(item, detect_input_language(item)) for item in items]


def validate_word_pair(english, chinese):
    english = normalize_english(english)
    chinese = chinese.strip()
    if not english or not chinese:
        raise ValueError("英文和中文都不能为空")

    if contains_chinese(english) and is_mostly_english(chinese):
        english, chinese = chinese, english

    if not is_mostly_english(english):
        raise ValueError(f"英文无效：{english}")
    if not contains_chinese(chinese):
        raise ValueError(f"中文无效：{chinese}")
    if english.lower() == chinese.lower():
        raise ValueError("英文和中文不能相同")

    return english, chinese


def split_manual_pair(raw_pair):
    raw_pair = raw_pair.strip()
    quoted = re.match(r'^(["\'])(.+?)\1\s+(.+)$', raw_pair)
    if quoted:
        return quoted.group(2).strip(), quoted.group(3).strip()
    if "|" in raw_pair:
        english, chinese = raw_pair.split("|", 1)
        return english.strip(), chinese.strip()
    match = CHINESE_PATTERN.search(raw_pair)
    if match:
        english = raw_pair[: match.start()].strip()
        chinese = raw_pair[match.start() :].strip()
        if english and chinese:
            return english, chinese
    parts = raw_pair.split()
    if len(parts) < 2:
        raise ValueError(f"「{raw_pair}」格式错误，应为：英文 中文")
    return parts[0], " ".join(parts[1:])


def validate_manual_pair(raw_pair):
    english, chinese = split_manual_pair(raw_pair)
    return validate_word_pair(english, chinese)


def extract_first_meaning(text):
    text = re.sub(r"^\[[^\]]+\]", "", text.strip())
    text = re.sub(r"^[a-z]+\.\s*", "", text.strip(), flags=re.IGNORECASE)
    parts = re.split(r"[;；]", text)
    meaning = parts[0].strip()
    if not meaning:
        raise ValueError("未获取到翻译结果")
    return meaning


def _http_get_json(url, headers=None, data=None, timeout=10):
    logger.debug(f"HTTP GET: {url[:80]}...")
    request = urllib.request.Request(url, data=data, headers=headers or {})
    try:
        with urllib.request.urlopen(request, timeout=timeout) as response:
            return json.loads(response.read().decode("utf-8"))
    except Exception as exc:
        logger.warning(f"HTTP request failed for {url[:60]}...: {exc}")
        raise


def _fetch_from_youdao(text):
    params = urllib.parse.urlencode({"q": text, "num": "5", "doctype": "json"})
    data = _http_get_json(
        f"{YOUDAO_SUGGEST_URL}?{params}",
        headers={"User-Agent": USER_AGENT},
    )
    entries = data.get("data", {}).get("entries", [])
    if not entries:
        raise ValueError("有道词典未返回结果")
    return extract_first_meaning(entries[0]["explain"])


def _fetch_from_baidu(text):
    payload = urllib.parse.urlencode({"kw": text}).encode("utf-8")
    data = _http_get_json(
        BAIDU_SUG_URL,
        data=payload,
        headers={
            "User-Agent": USER_AGENT,
            "Content-Type": "application/x-www-form-urlencoded",
        },
    )
    if data.get("errno") != 0 or not data.get("data"):
        raise ValueError("百度翻译未返回结果")
    return extract_first_meaning(data["data"][0]["v"])


def _fetch_from_google(text, source_lang, target_lang):
    params = urllib.parse.urlencode(
        {
            "client": "gtx",
            "sl": source_lang,
            "tl": target_lang,
            "dt": "t",
            "q": text,
        }
    )
    data = _http_get_json(
        f"{TRANSLATE_URL}?{params}",
        headers={"User-Agent": USER_AGENT},
    )
    result = "".join(part[0] for part in data[0] if part and part[0]).strip()
    if not result:
        raise ValueError("Google 翻译未返回结果")
    return result


def _translate_with_fallback(text, providers, normalize):
    last_error = None
    for fetcher in providers:
        try:
            return normalize(fetcher(text))
        except ValueError:
            raise
        except (urllib.error.URLError, TimeoutError, KeyError, IndexError, json.JSONDecodeError) as exc:
            last_error = exc
            continue
    if last_error is not None:
        raise ValueError("翻译失败，请检查网络")
    raise ValueError("翻译服务暂时不可用")


def fetch_english_translation(chinese_text):
    chinese_text = validate_chinese_input(chinese_text, "中文内容")

    def normalize(result):
        english = normalize_english(result)
        if not is_mostly_english(english):
            raise ValueError(f"翻译结果不是有效英文：{english}")
        return english

    return _translate_with_fallback(
        chinese_text,
        (
            _fetch_from_youdao,
            _fetch_from_baidu,
            lambda text: _fetch_from_google(text, "zh-CN", "en"),
        ),
        normalize,
    )


def fetch_chinese_translation(english_text):
    english_text = validate_english_input(english_text, "英文内容")

    def normalize(result):
        chinese = result.strip()
        if not contains_chinese(chinese):
            raise ValueError(f"翻译结果不是有效中文：{chinese}")
        return chinese

    return _translate_with_fallback(
        english_text,
        (
            _fetch_from_youdao,
            _fetch_from_baidu,
            lambda text: _fetch_from_google(text, "en", "zh-CN"),
        ),
        normalize,
    )


def translate_item_to_pair(text, language):
    if language == "zh":
        chinese = text.strip()
        english = fetch_english_translation(chinese)
        return validate_word_pair(english, chinese)
    english = normalize_english(text)
    chinese = fetch_chinese_translation(english)
    return validate_word_pair(english, chinese)


