    def init_builtin_dictionary(self):
        try:
            self.school_dict.load()
            self.dict_ready = True
        except FileNotFoundError:
            index_script = os.path.join(os.path.dirname(__file__), "build_dictionary_index.py")
            if os.path.isfile(index_script):
                try:
                    from build_dictionary_index import build

                    build()
                    self.school_dict.load()
                    self.dict_ready = True
                except Exception as exc:
                    self.dict_ready = False
                    # 只有 pick_status 已创建时才更新
                    if hasattr(self, "pick_status"):
                        self.pick_status.config(
                            text=f"内置词库加载失败：{exc}",
                            foreground=COLORS["danger"],
                        )
                    return
            else:
                self.dict_ready = False
                # 只有 pick_status 已创建时才更新
                if hasattr(self, "pick_status"):
                    self.pick_status.config(
                        text="未找到内置词库，请先运行 build_dictionary_index.py",
                        foreground=COLORS["danger"],
                    )
                return
        if hasattr(self, "stage_combo"):
            self.refresh_pick_stages()

